#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n,cnt=0;    cin >> n;        vll a(n);    for(int i=0; i<n; i++) cin >> a[i];    for(int i=n-2;i>=0;i--){            while(a[i]>=a[i+1]){                a[i]=int(a[i]/2);                cnt++;                if(a[i]==0) break;                            }            if(a[i]==0 && a[i+1]==0){                cnt=-1;                break;            }    }         cout << cnt << "\n";}       // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}